TRANSLATIONS = {
    'ar': {},
    'en': AR_TO_EN,
}

SUPPORTED_LANGS = {'ar', 'en'}


def catalog_for(lang: str = 'en') -> dict[str, str]:
    lang = 'en' if str(lang or '').lower().startswith('en') else 'ar'
    return dict(TRANSLATIONS.get(lang, {}))
